 1	import { type FC, type PropsWithChildren, useState } from 'react';
 2	
 3	import {
 4	  Button,
 5	  ButtonVariant,
 6	  ExpandableSection,
 7	  type ExpandableSectionProps,
 8	  Flex,
 9	  FlexItem,
10	  Title,
11	} from '@patternfly/react-core';
12	import { useForkliftTranslation } from '@utils/i18n';
13	
14	import './ExpandableReviewSection.style.scss';
15	
16	type ExpandableReviewSectionProps = PropsWithChildren &
17	  Pick<ExpandableSectionProps, 'title'> & {
18	    onEditClick?: () => void;
19	    testId?: string;
20	  };
21	
22	const ExpandableReviewSection: FC<ExpandableReviewSectionProps> = ({
23	  children,
24	  onEditClick,
25	  testId,
26	  title,
27	}) => {
28	  const { t } = useForkliftTranslation();
29	  const [isExpanded, setIsExpanded] = useState(true);
30	
31	  return (
32	    <ExpandableSection
33	      className="expandable-review-section pf-v5-w-100"
34	      data-testid={testId}
35	      toggleContent={
36	        <Flex
37	          justifyContent={{ default: 'justifyContentSpaceBetween' }}
38	          alignItems={{ default: 'alignItemsCenter' }}
39	        >
40	          <Title headingLevel="h3">{title}</Title>
41	
42	          <FlexItem alignSelf={{ default: 'alignSelfFlexStart' }}>
43	            <Button
44	              variant={ButtonVariant.link}
45	              onClick={(event) => {
46	                event.stopPropagation();
47	
48	                onEditClick?.();
49	              }}
50	            >
51	              {t('Edit step')}
52	            </Button>
53	          </FlexItem>
54	        </Flex>
55	      }
56	      isExpanded={isExpanded}
57	      onToggle={(_, isSectionExpanded) => {
58	        setIsExpanded(isSectionExpanded);
59	      }}
60	      allowFullScreen
61	    >
62	      <div className="pf-v6-u-p-lg pf-v6-u-pt-0">{children}</div>
63	    </ExpandableSection>
64	  );
65	};
66	
67	export default ExpandableReviewSection;

